// ── Injection function ──────────────────────────────────────────────────────

function injectFirstGradeFields(filePath, newFields) {
  const src = fs.readFileSync(filePath, 'utf8');
  // Find the unique pattern: end of first-grade section + second-grade start
  const marker = /\n    \},\n    'second-grade':/;
  const match = src.match(marker);
  if (!match) {
    throw new Error(`Could not find first-grade/second-grade boundary in ${filePath}`);
  }
  // Insert the new fields before the closing }, of the first-grade section
  const insertPos = match.index;
  const updated = src.slice(0, insertPos) + '\n' + newFields + '\n    },\n    \'second-grade\':' + src.slice(match.index + match[0].length);
  fs.writeFileSync(filePath, updated, 'utf8');
  console.log(`  Updated ${path.basename(path.dirname(filePath))}/${path.basename(filePath)}`);
}

